__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"GLOSSARY",{enumerable:!0,get:function(){return n}}),e.getGlossaryEntry=function(l){return n[l]};const n={totem:{term:'Totem Hayvan',short:'Seninle do\u011fan, \xf6m\xfcr boyu kalan ruh hayvan\u0131.',long:"Totem hayvan, her insan\u0131n do\u011fas\u0131nda ta\u015f\u0131d\u0131\u011f\u0131 ruhsal e\u015flik\xe7idir. \u015eamanik geleneklerden gelen bu kavram, bir insan\u0131n temel enerjisini, g\xfc\xe7l\xfc yanlar\u0131n\u0131 ve gizli yeteneklerini temsil eden hayvan fig\xfcr\xfcne i\u015faret eder.\n\nTotem de\u011fi\u015fmez \u2014 seninle do\u011far, seninle geli\u015fir. Onu tan\u0131mak, kendini tan\u0131man\u0131n en eski yollar\u0131ndan biridir."},nagual:{term:'Nagual',short:'Belirli bir d\xf6nemde sana e\u015flik eden ge\xe7ici rehber.',long:"Nagual, Mezoamerikan ve \u015famanik geleneklerden gelen bir kavramd\u0131r. Totem hayvan\u0131n seninle do\u011far, \xf6m\xfcr boyu kal\u0131r; nagual ise belirli bir d\xf6neminde sana e\u015flik eden ge\xe7ici bir rehberdir.\n\nBir s\u0131nav, bir d\xf6n\xfc\u015f\xfcm, bir kriz an\u0131nda yan\u0131na gelir. G\xf6revini tamamlay\u0131nca yerini ba\u015fka bir rehbere b\u0131rak\u0131r. Bu uygulamada haftal\u0131k olarak de\u011fi\u015fen evrensel bir nagual ve do\u011fum haritana g\xf6re belirlenen ki\u015fisel naguelin g\xf6sterilir."},mit:{term:'Mit',short:'Ruhun kar\u015f\u0131la\u015ft\u0131\u011f\u0131 sembolik bir g\xfc\xe7 \u2014 G\xf6lge, E\u015fik, \u015eim\u015fek...',long:"Mitler, hayvan bi\xe7iminde de\u011fil de sembolik g\xfc\xe7 olarak gelen ruh rehberleridir: G\xf6lge, Ayna, K\xf6pr\xfc, E\u015fik, \u015eim\u015fek, Volkan...\n\nJung'un arketipleri gibi, mitler bilin\xe7alt\u0131n\u0131n dilini ta\u015f\u0131r. Kar\u015f\u0131na \xe7\u0131kan mit, o anda ruhunun hangi \xf6\u011freniyle kar\u015f\u0131 kar\u015f\u0131ya oldu\u011funu g\xf6sterir. Mitler S\xf6zl\xfc\u011f\xfc'nde 50 sembolik g\xfc\xe7 bulabilirsin."},hayatYolu:{term:'Hayat Yolu Say\u0131s\u0131',short:'Do\u011fum tarihinin numerolojik \xf6zetidir \u2014 ana enerjini g\xf6sterir.',long:"Hayat yolu say\u0131s\u0131, do\u011fum tarihinin t\xfcm rakamlar\u0131n\u0131n tek bir say\u0131ya indirgenmesiyle bulunur (\xf6rn. 15.06.1990 \u2192 1+5+0+6+1+9+9+0=31\u21924).\n\n1'den 9'a, ek olarak usta say\u0131lar\u0131 11, 22 ve 33. Her say\u0131 belirli bir arketipi temsil eder: \xd6nc\xfc, Arabulucu, Yarat\u0131c\u0131, Yap\u0131c\u0131, \xd6zg\xfcr Ruh, Sevgi El\xe7isi, Bilge, G\xfc\xe7 ve \xd6\u011fretmen. Hayat yolun, d\xfcnyaya geldi\u011fin temel g\xf6revin sembol\xfcd\xfcr."},numeroloji:{term:'Numeroloji',short:'Say\u0131lar\u0131n ard\u0131ndaki ruhsal anlamlar\u0131 okuma sanat\u0131.',long:"Numeroloji, say\u0131lar\u0131n sembolik ve ruhsal anlamlar\u0131n\u0131 inceleyen antik bir bilgi sistemidir. Do\u011fum tarihin ve isminin harfleri, ki\u015fili\u011finin farkl\u0131 katmanlar\u0131n\u0131 g\xf6steren say\u0131lara d\xf6n\xfc\u015ft\xfcr\xfcl\xfcr.\n\nD\xf6rt temel say\u0131: Hayat Yolu (kaderin), \u0130fade (yetenekler), Ruh \u0130ste\u011fi (i\xe7sel arzular) ve Ki\u015filik (d\u0131\u015fa yans\u0131tt\u0131\u011f\u0131n y\xfcz). Her biri farkl\u0131 bir aynad\u0131r."},ifade:{term:'\u0130fade Say\u0131s\u0131',short:'\u0130sminin harflerinden gelen \u2014 do\u011fal yeteneklerin ve potansiyelin.',long:"\u0130fade say\u0131s\u0131 (Destiny / Expression number), tam isminin (isim+soyisim) harflerinin say\u0131sal kar\u015f\u0131l\u0131klar\u0131n\u0131n toplam\u0131ndan bulunur. Bu say\u0131, do\u011fu\u015ftan getirdi\u011fin yetenekleri ve hayat\u0131nda ger\xe7ekle\u015ftirmen gereken potansiyeli temsil eder."},ruhIstegi:{term:'Ruh \u0130ste\u011fi Say\u0131s\u0131',short:'\u0130smindeki sesli harflerden \u2014 i\xe7sel motivasyonun.',long:"Ruh \u0130ste\u011fi (Soul Urge / Heart's Desire), ismindeki sesli harflerin numerolojik toplam\u0131d\u0131r. Sana ne yapt\u0131\u011f\u0131n\u0131 de\u011fil, neden yapt\u0131\u011f\u0131n\u0131 s\xf6yler. Gizli motivasyonlar\u0131n, i\xe7sel arzular\u0131n ve neyle ger\xe7ekten doydu\u011funun g\xf6stergesidir."},kisilik:{term:'Ki\u015filik Say\u0131s\u0131',short:'\u0130smindeki sessiz harflerden \u2014 d\xfcnyaya g\xf6sterdi\u011fin y\xfcz.',long:"Ki\u015filik say\u0131s\u0131, ismindeki sessiz harflerin numerolojik toplam\u0131d\u0131r. \u0130lk izlenim olarak d\u0131\u015fa yans\u0131tt\u0131\u011f\u0131n enerjiyi, ba\u015fkalar\u0131n\u0131n seni nas\u0131l alg\u0131lad\u0131\u011f\u0131n\u0131 g\xf6sterir. Maskeyle ger\xe7ek aras\u0131nda bir k\xf6pr\xfcd\xfcr."},humanDesign:{term:'Human Design',short:'Astroloji, I Ching, \xe7akra ve Kabala\'y\u0131 birle\u015ftiren bir sistem.',long:"Human Design, 1987'de Ra Uru Hu taraf\u0131ndan geli\u015ftirilen modern bir ruhsal sistemdir. Do\u011fum bilgilerine g\xf6re 5 ana tipten birine aitsindir: Jenerat\xf6r, Manifesting Jenerat\xf6r, Projekt\xf6r, Manifestor veya Reflekt\xf6r.\n\nHer tipin kendine \xf6zg\xfc bir stratejisi (karar verme yolu) ve \"not-self\" temas\u0131 (yanl\u0131\u015f yolda oldu\u011funu hissettiren duygu) vard\u0131r. Kendi tasar\u0131m\u0131n\u0131 ya\u015famak, ak\u0131\u015fa girmenin anahtar\u0131d\u0131r."},"jenerat\xf6r":{term:'Jenerat\xf6r',short:'Ya\u015fam enerjisinin kayna\u011f\u0131. Strateji: Yan\u0131t vermek.',long:"Jenerat\xf6rler pop\xfclasyonun yakla\u015f\u0131k %37'sidir. Sakral merkezleri tan\u0131ml\u0131d\u0131r, yani derin bir i\xe7g\xfcd\xfcsel evet/hay\u0131r enerjisi ta\u015f\u0131rlar.\n\nStratejileri yan\u0131t vermektir \u2014 yani bir \u015feyi ba\u015flatmak yerine, hayat\u0131n onlara getirdi\u011fine evet veya hay\u0131r demek. Do\u011fru \u015feylere evet derlerse tatmin (satisfaction); yanl\u0131\u015flara evet derlerse hayal k\u0131r\u0131kl\u0131\u011f\u0131 (frustration) ya\u015farlar."},"manifestingJenerat\xf6r":{term:'Manifesting Jenerat\xf6r',short:'\xc7ok boyutlu, h\u0131zl\u0131 bir Jenerat\xf6r. Strateji: Yan\u0131t ver, harekete ge\xe7.',long:"Manifesting Jenerat\xf6rler, Jenerat\xf6r\xfcn sakral enerjisini Manifestor'un ba\u015flatma g\xfcc\xfcyle birle\u015ftirir. Birden fazla \u015feyi ayn\u0131 anda yapabilir, h\u0131zl\u0131 y\xf6n de\u011fi\u015ftirebilirler.\n\nStrateji: \xd6nce yan\u0131t ver (sakral\u0131n evet desin), sonra harekete ge\xe7 ve ad\u0131mlar\u0131n\u0131 ba\u015fkalar\u0131na bildir. Not-self temas\u0131 \xf6fke ve hayal k\u0131r\u0131kl\u0131\u011f\u0131d\u0131r."},"projekt\xf6r":{term:'Projekt\xf6r',short:'Sistemleri ve insanlar\u0131 derinden g\xf6ren rehber. Strateji: Davet bekle.',long:"Projekt\xf6rler pop\xfclasyonun %20'sidir. Sakral merkezleri tan\u0131ml\u0131 de\u011fildir; s\xfcrekli enerji \xfcretmezler. Ama insanlar\u0131 ve sistemleri derinden okuma yetenekleri vard\u0131r.\n\nStrateji: Davet beklemek. Davet edilmeden \xf6nc\xfcl\xfck etmeye \xe7al\u0131\u015f\u0131rlarsa ac\u0131 (bitterness) ya\u015farlar. Do\u011fru davet geldi\u011finde ise muazzam rehberlik enerjisi sunarlar."},manifestor:{term:'Manifestor',short:'Ba\u011f\u0131ms\u0131z ba\u015flat\u0131c\u0131. Strateji: Bildirmek.',long:"Manifestor'lar pop\xfclasyonun %9'udur. Do\u011fal ba\u015flat\u0131c\u0131lard\u0131r \u2014 yeni d\xf6ng\xfcler a\xe7abilir, hareket yaratabilirler. Sakral merkezleri tan\u0131ml\u0131 de\u011fildir.\n\nStrateji: Harekete ge\xe7meden \xf6nce etraf\u0131ndakilere bildirmek. Bu, kontrol kayb\u0131 korkusuyla do\u011fan \xf6fkeyi (anger) \xf6nler. \xd6zg\xfcrl\xfck onlar i\xe7in hayatidir."},"reflekt\xf6r":{term:'Reflekt\xf6r',short:'Toplumun aynas\u0131. Strateji: 28 g\xfcn bekle.',long:"Reflekt\xf6rler pop\xfclasyonun yaln\u0131zca %1'idir. Hi\xe7bir merkezleri tan\u0131ml\u0131 de\u011fildir \u2014 yani \xe7evrenin enerjisini tamamen yans\u0131t\u0131rlar. Bir toplulu\u011fun sa\u011fl\u0131\u011f\u0131n\u0131n aynas\u0131d\u0131rlar.\n\nStrateji: \xd6nemli kararlar i\xe7in Ay'\u0131n 28 g\xfcnl\xfck d\xf6ng\xfcs\xfcn\xfc beklemek. Bu s\xfcre boyunca ayn\u0131 karar\u0131 farkl\u0131 ortamlarda hissetmek, do\u011fru cevab\u0131 verir. Not-self temas\u0131 hayal k\u0131r\u0131kl\u0131\u011f\u0131d\u0131r."},notSelf:{term:'Not-Self Tema',short:'Yanl\u0131\u015f yolda oldu\u011funu hissettiren duygu.',long:"Human Design'da her tipin kendine \xf6zg\xfc bir \"not-self\" temas\u0131 vard\u0131r \u2014 bu, kendi tasar\u0131m\u0131nla uyumsuz ya\u015fad\u0131\u011f\u0131nda hissedilen duygudur.\n\n\u2022 Jenerat\xf6r/Manifesting Jenerat\xf6r: Hayal k\u0131r\u0131kl\u0131\u011f\u0131\n\u2022 Projekt\xf6r: Ac\u0131, k\u0131zg\u0131nl\u0131k\n\u2022 Manifestor: \xd6fke\n\u2022 Reflekt\xf6r: Hayal k\u0131r\u0131kl\u0131\u011f\u0131\n\nBu duygu, y\xf6n de\u011fi\u015ftirmen i\xe7in gelen i\xe7sel sinyaldir \u2014 yarg\u0131lay\u0131p bast\u0131rmak de\u011fil, dinlemek gerekir."},unsur:{term:'Unsur (Element)',short:'Do\u011fan\u0131n d\xf6rt temel niteli\u011fi: Ate\u015f, Su, Toprak, Hava.',long:"Unsurlar, antik d\xfcnyan\u0131n d\xf6rt temel yap\u0131 ta\u015f\u0131d\u0131r. Her unsur belirli bir mizac\u0131 ve enerjiyi temsil eder:\n\n\u25b3 ATE\u015e \u2014 Tutku, irade, d\xf6n\xfc\u015f\xfcm, eylem\n\u25bd SU \u2014 Duygu, sezgi, ak\u0131\u015f, derinlik\n\u2295 TOPRAK \u2014 Beden, sab\u0131r, ger\xe7eklik, k\xf6k\n\u25cb HAVA \u2014 Ak\u0131l, ileti\u015fim, fikir, hareket\n\nDo\u011fdu\u011fun mevsim ve y\u0131ld\u0131z hareketleri sana bask\u0131n bir unsur verir. Bu unsuru tan\u0131mak, kendi do\u011fas\u0131n\u0131n ritmiyle uyum kurmay\u0131 sa\u011flar."},arketip:{term:'Arketip',short:'T\xfcm insanl\u0131\u011f\u0131n payla\u015ft\u0131\u011f\u0131 evrensel sembolik fig\xfcr.',long:"Arketip, Carl Jung'un derinlik psikolojisindeki temel kavramd\u0131r. Kollektif bilin\xe7alt\u0131nda yer alan, t\xfcm k\xfclt\xfcrlerce payla\u015f\u0131lan evrensel fig\xfcrlerdir: Anne, Baba, Kahraman, Bilge, G\xf6lge, Trickster...\n\nHayvanlar da arketip olarak gelir \u2014 Y\u0131lan (d\xf6n\xfc\u015f\xfcm), Kartal (y\xfcksek vizyon), Kurt (sezgi). Kar\u015f\u0131na \xe7\u0131kan arketip, i\xe7indeki o yan\u0131n uyanmas\u0131 gerekti\u011fini s\xf6yler."},golge:{term:'G\xf6lge (Shadow)',short:'Bilincimizde reddetti\u011fimiz, bast\u0131rd\u0131\u011f\u0131m\u0131z yan\u0131m\u0131z.',long:"Jung'un \"g\xf6lge\" kavram\u0131, ki\u015fili\u011fimizin g\xf6rmek istemedi\u011fimiz, bast\u0131rd\u0131\u011f\u0131m\u0131z ya da utand\u0131\u011f\u0131m\u0131z yanlar\u0131n\u0131 ifade eder. Bunlar k\xf6t\xfc de\u011fildir \u2014 sadece bilin\xe7li benli\u011fimizin reddetti\u011fi par\xe7alard\u0131r.\n\nG\xf6lge i\u015fi, bu yanlar\u0131 g\xf6rmek, anlamak ve b\xfct\xfcnle\u015ftirmektir. Tan\u0131mlanmayan g\xf6lge d\u0131\u015far\u0131da \u2014 ba\u015fkalar\u0131nda ya da olaylarda \u2014 kendini g\xf6sterir. Tan\u0131nd\u0131\u011f\u0131nda ise muazzam bir g\xfcce d\xf6n\xfc\u015f\xfcr."},kisiselYil:{term:'Ki\u015fisel Y\u0131l',short:'Numerolojik y\u0131l\u0131na \xf6zg\xfc tema \u2014 9 y\u0131ll\u0131k d\xf6ng\xfcn\xfcn hangi ad\u0131m\u0131nda oldu\u011fun.',long:"Ki\u015fisel y\u0131l, do\u011fum g\xfcn\xfcn\xfcn ve ay\u0131n\u0131n i\xe7inde bulundu\u011fun y\u0131lla toplanmas\u0131yla bulunur. 1'den 9'a kadar bir d\xf6ng\xfc olu\u015fturur:\n\n1: Ba\u015flang\u0131\xe7 \xb7 2: \u0130li\u015fki \xb7 3: Yarat\u0131m \xb7 4: Temel \xb7 5: De\u011fi\u015fim \xb7 6: Sorumluluk \xb7 7: \u0130\xe7e d\xf6n\xfc\u015f \xb7 8: Hasat \xb7 9: Tamamlanma\n\nHer y\u0131l farkl\u0131 bir ders sunar. Hangi y\u0131lda oldu\u011funu bilmek, y\u0131l\u0131n ak\u0131\u015f\u0131yla uyum kurmana yard\u0131mc\u0131 olur."},rehber:{term:'Rehber Hayvan',short:'Ki\u015fili\u011finin ve enerjinin yans\u0131d\u0131\u011f\u0131 totem hayvan.',long:"Rehber hayvan, bu uygulamada totem hayvan\u0131n e\u015f anlaml\u0131s\u0131 olarak kullan\u0131l\u0131r. Do\u011fum tarihin, mevsimin, saatin ve ki\u015filik sorular\u0131n \xfczerinden hangi hayvan\u0131n enerjisini en g\xfc\xe7l\xfc ta\u015f\u0131d\u0131\u011f\u0131n belirlenir.\n\nRehber hayvan\u0131n seni temsil eden de\u011fil, sana e\u015flik eden bir \xf6\u011fretmendir. Onun \xf6zelliklerini incelemek, kendi yanlar\u0131n\u0131 da daha g\xf6r\xfcn\xfcr k\u0131lar."}}},848,[]);
